import React, { useEffect, useState } from 'react'; 
import axios from 'axios'; 
const Ranking = () => { 
  const [songs, setSongs] = useState([]); 
  useEffect(() => { axios.get('http://localhost:5000/api/songs').then(res => setSongs(res.data)); }, []); 
  return ( 
    <div style={{ padding: '40px', maxWidth: '800px', margin: '0 auto' }}> 
      <h2 style={{ textAlign: 'center' }}>🏆 BẢNG XẾP HẠNG</h2> 
      {songs.map((s, i) => ( 
        <div key={s._id} style={{ display: 'flex', alignItems: 'center', padding: '15px', borderBottom: '1px solid #eee' }}> 
          <h3 style={{ marginRight: '20px', color: '#1db954' }}>#{i+1}</h3> 
          <img src={`http://localhost:5000${s.imageUrl}`} style={{ width: '50px', height: '50px', borderRadius: '5px', marginRight: '15px' }} /> 
          <div><b>{s.title}</b><p style={{ margin: 0, fontSize: '14px', color: '#666' }}>{s.artist}</p></div> 
        </div> 
      ))} 
    </div> 
  ); 
}; export default Ranking;
